const keywords = [
  'performance marketing',
  'marketing automation',
  'crm marketing',
  'marketing technology',
  'email marketing',
  'growth marketing',
  'martech',
  'demand generation',
  'marketing operations'
];
const query = keywords.map(k => `"${k}"`).join(' OR ');
return [{ json: {
  query,
  location: 'Berlin, Germany',
  services: keywords
}}];

const response = items[0]?.json ?? {};
const results = response.data ?? [];
return results.map(job => ({ json: job }));

return items.filter(item => {
  const city = (item.json.job_city || item.json.job_location || '').toString().toLowerCase();
  return city.includes('berlin');
});

const serviceCatalog = [
  { keyword: 'marketing automation', label: 'Marketing Automation Implementation' },
  { keyword: 'crm', label: 'CRM Architecture & Integrations' },
  { keyword: 'performance', label: 'Performance Marketing Campaigns' },
  { keyword: 'email', label: 'Lifecycle & Email Marketing' },
  { keyword: 'martech', label: 'MarTech Stack Advisory' },
  { keyword: 'growth', label: 'Growth Marketing' }
];
return items.map(item => {
  const job = item.json;
  const description = (job.job_description || '').toLowerCase();
  const matches = serviceCatalog
    .filter(entry => description.includes(entry.keyword))
    .map(entry => entry.label);
  let domain = job.employer_website || job.job_apply_link || '';
  if (domain) {
    try {
      const parsed = new URL(domain.startsWith('http') ? domain : `https://${domain}`);
      domain = parsed.hostname.replace(/^www\./, '');
    } catch (error) {
      domain = domain.replace(/^https?:\/\//, '').split('/')[0].replace(/^www\./, '');
    }
  }
  return {
    json: {
      jobId: job.job_id,
      jobTitle: job.job_title,
      companyName: job.employer_name || job.job_publisher || 'Unknown Company',
      jobCity: job.job_city || job.job_location,
      jobCountry: job.job_country,
      jobApplyLink: job.job_apply_link,
      jobDescription: job.job_description,
      jobPostedAt: job.job_posted_at_datetime_utc,
      salaryMin: job.job_min_salary,
      salaryMax: job.job_max_salary,
      salaryCurrency: job.job_salary_currency,
      serviceMatches: matches,
      companyDomain: domain,
      source: job.job_publisher,
      raw: job
    }
  };
});

const staticData = this.getWorkflowStaticData('global');
if (!staticData.seenJobIds) {
  staticData.seenJobIds = [];
}
const seen = new Set(staticData.seenJobIds);
const fresh = [];
for (const item of items) {
  const jobId = item.json.jobId;
  if (!jobId || seen.has(jobId)) {
    continue;
  }
  fresh.push(item);
  seen.add(jobId);
}
staticData.seenJobIds = Array.from(seen).slice(-200);
return fresh;

return items.map(item => {
  const response = item.json || {};
  const emails = response.data?.emails || [];
  const prioritized = emails.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
  const chosen = prioritized.find(email => email.type === 'personal') || prioritized[0] || null;
  return {
    json: {
      contactEmail: chosen ? chosen.value : null,
      contactName: chosen ? `${chosen.first_name || ''} ${chosen.last_name || ''}`.trim() : null,
      contactPosition: chosen ? chosen.position : null,
      confidence: chosen ? chosen.confidence : null,
      sources: chosen ? chosen.sources : [],
      hunterRaw: response.data || {}
    }
  };
});

return items.map(item => {
  const salary = item.json.salaryMin || item.json.salaryMax
    ? [item.json.salaryMin, item.json.salaryMax].filter(Boolean).join(' - ') + (item.json.salaryCurrency ? ` ${item.json.salaryCurrency}` : '')
    : 'N/A';
  const matchList = (item.json.serviceMatches || []).map(match => `- ${match}`).join('\n');
  const contactName = item.json.contactName || 'سلام';
  const source = item.json.source || 'JSearch';
  const jobTitle = item.json.jobTitle || 'Opportunity';
  const companyName = item.json.companyName || 'there';
  const template = `{{greeting}} ${contactName},\n\nمن {{senderName}} از تیم Dopamine Marketic هستم. ما به شرکت‌های برلینی کمک می‌کنیم تا با راهکارهای داده‌محور رشد سریعی داشته باشند. فرصت ${jobTitle} شما در ${companyName} را دیدیم (${source}) و فکر کردیم شاید بتوانیم در اجرای استراتژی‌های بازاریابی‌تان همراهتان باشیم.\n\nخلاصه چیزهایی که از شرح شغل برداشتیم:\n${matchList || '- تمرکز روی بازاریابی داده محور'}\n\nما می‌توانیم ظرف چند روز:\n- پیاده‌سازی Journey های اتوماسیون بازاریابی را انجام دهیم.\n- داشبوردهای RealMetrics را برای تیم فروش و مارکتینگ‌تان فعال کنیم.\n- با تیم شما برای جذب لیدهای باکیفیت کمپین مشترک اجرا کنیم.\n\nاگر ۲۰ دقیقه وقت داشته باشید خوشحال می‌شویم چند نمونه کار مرتبط (مثل RealMetrics برای استارتاپ‌های برلینی) را نشان دهیم. مناسبت‌ترین زمان برای شما کی است؟\n\nبا احترام،\n{{senderName}}\nDopamine Marketic\n{{senderEmail}}`;
  return {
    json: {
      jobId: item.json.jobId,
      toEmail: item.json.contactEmail,
      contactName,
      jobTitle,
      companyName,
      subject: `پیشنهاد همکاری برای ${companyName} - ${jobTitle}`,
      emailBody: template,
      jobApplyLink: item.json.jobApplyLink,
      salary,
      matchList,
      source,
      serviceMatches: item.json.serviceMatches,
      hunterConfidence: item.json.confidence
    }
  };
});
